def norm_text(s):
    return normalize_ar(s)

def lcs_length(a,b):
    # Classic dynamic programming for LCS length
    n,m = len(a), len(b)
    # memory heavy; but strings are small; fine
    dp = [ [0]*(m+1) for _ in range(n+1) ]
    for i in range(n):
        ai = a[i]
        for j in range(m):
            if ai == b[j]:
                dp[i+1][j+1] = dp[i][j]+1
            else:
                dp[i+1][j+1] = dp[i+1][j] if dp[i+1][j]>dp[i][j+1] else dp[i][j+1]
    return dp[n][m]

def lcs_ratio(a,b):
    a2 = norm_text(a)
    b2 = norm_text(b)
    L = lcs_length(a2,b2)
    return L / max(len(a2),len(b2))

